module RefModule(
    input [7:0] A,
    input [7:0] B,
    input SEL,
    output reg [7:0] OUT
);wire [7:0] obf_negB;
    assign obf_negB = (~B) + 1;

    always @(*) begin
        if (SEL == 0) begin
            OUT = A + B;
        end else begin
            OUT = A + obf_negB;
        end
    end

endmodule
